=== REQTRACE COVERAGE REPORT ===") print(f"Total Requirements: {report.total_requirements}") print(f"Implemented (>=100%): {report.implemented_requirements}") print(f"Partial (<100%): {report.partial_requirements}") print(f"Missing (0%): {report.missing_requirements}
") if report.source_stats: print("--- SOURCE CODE COVERAGE ---") print(f"Total Source Files: {report.source_stats.total_files}") if report.source_stats.disabled_files > 0: print(f"Disabled Files: {report.source_stats.disabled_files}") print(f"Total Source Lines: {report.source_stats.total_lines}") print(f"Mapped Lines: {report.source_stats.mapped_lines}") print(f"Unmapped Lines: {report.source_stats.unmapped_lines}
") print("--- DETAILS ---") for req_id, cov in report.coverage_details.items(): status = "✅ IMPLEMENTED" if cov.is_implemented else ("⚠️ PARTIAL" if cov.total_percentage > 0 else "❌ MISSING") print(f"[{status}] {req_id} - Coverage: {cov.total_percentage}%") if report.unmatched_traces: print("
--- WARNING: UNMATCHED TRACE TAGS ---") print("The following trace tags refer to unknown requirement IDs.") for trace in report.unmatched_traces: pct_str = f"({trace.percentage}%)" if trace.percentage else "" print(f"Unknown ID: '{trace.req_id}' {pct_str} at {trace.file_path}:{trace.line_start}-{trace.line_end}") # Exit with error code if coverage is not 100% # (This fails the CI pipeline intentionally if requirements aren't met!) if report.missing_requirements > 0 or report.partial_requirements > 0: sys.exit(1) sys.exit(0) # @trace-end: REQ-CLI except Exception as e: # pylint: disable=broad-exception-caught log.error("Error running reqtrace: %s", e) sys.exit(2)

